import type { FloorContentProvider } from "../../engine/run/loop.js";
import type { BotPolicy } from "./types.js";
import { runBot, type BotRunResult, type RunBotOptions } from "./driver.js";

export type BotBatchRow = {
  readonly policy: BotPolicy["name"];
  readonly seed: string;
  readonly terminal: string;
  readonly depth: number;
  readonly turns: number;
  readonly kills: number;
  readonly hpRetention: number;
  readonly itemUses: number;
  readonly tracePath: string;
};

export type BotBatchResult = {
  readonly rows: readonly BotBatchRow[];
  readonly runs: readonly BotRunResult[];
};

export const runBotBatch = (
  policies: readonly BotPolicy[],
  seeds: readonly string[],
  providerFactory: () => FloorContentProvider,
  maxTurns: number,
  options: RunBotOptions = {},
): BotBatchResult => {
  const runs = policies.flatMap((policy) =>
    seeds.map((seed) =>
      runBot(policy, seed, providerFactory(), maxTurns, {
        ...options,
        runId: `bot-${policy.name}-${seed}`,
      }),
    ),
  );

  return {
    runs,
    rows: runs.map((run) => ({
      policy: run.policy,
      seed: run.seed,
      terminal: run.outcome.terminal,
      depth: run.outcome.depth,
      turns: run.outcome.turns,
      kills: run.outcome.kills,
      hpRetention: run.outcome.hpRetention,
      itemUses: run.outcome.itemUses,
      tracePath: run.trace.path,
    })),
  };
};

export const formatBotOutcomeTable = (
  rows: readonly BotBatchRow[],
): string => {
  const headers = [
    "policy",
    "seed",
    "terminal",
    "depth",
    "turns",
    "kills",
    "hp%",
    "itemUses",
  ] as const;
  const body = rows.map((row) => [
    row.policy,
    row.seed,
    row.terminal,
    row.depth.toString(),
    row.turns.toString(),
    row.kills.toString(),
    Math.round(row.hpRetention * 100).toString(),
    row.itemUses.toString(),
  ]);
  const widths = headers.map((header, index) =>
    Math.max(header.length, ...body.map((row) => row[index]?.length ?? 0)),
  );
  const line = (cells: readonly string[]) =>
    cells
      .map((cell, index) => cell.padEnd(widths[index] ?? cell.length))
      .join(" | ");

  return [
    line(headers),
    widths.map((width) => "-".repeat(width)).join("-|-"),
    ...body.map(line),
  ].join("\n");
};

import "../../engine/effects/core.js";
import "../../engine/effects/spatial.js";
import "../../engine/items/triggers.js";
import "../../engine/npc/dialogue.js";
import "../../engine/systems/combat.js";
import "../../engine/systems/inventory.js";
import "../../engine/systems/movement.js";
import "../../engine/systems/player.js";
import "../../engine/systems/status.js";

import { summarizeRun } from "../../engine/run/endings.js";
import {
  startRun,
  stepRun,
  type FloorContentProvider,
  type RunAction,
} from "../../engine/run/loop.js";
import type { RunEvent } from "../../engine/run/events.js";
import type { GameState, TerminalStatus } from "../../engine/state/index.js";
import {
  createTraceRecorder,
  traceRunId,
  type TraceContentRef,
  type TraceTurnLine,
  type TraceWriter,
} from "../trace/recorder.js";
import {
  createBotStateView,
  createEmptyBotMemory,
  updateBotMemory,
} from "./view.js";
import type { BotMemory, BotPolicy, BotStateView } from "./types.js";
import { actionKey, fallbackAction, hasAction } from "./policies/helpers.js";

export type BotOutcome = {
  readonly terminal: TerminalStatus;
  readonly depth: number;
  readonly turns: number;
  readonly kills: number;
  readonly hpRetention: number;
  readonly itemUses: number;
  readonly maxTurnsHit: boolean;
};

export type BotTrace = {
  readonly path: string;
  readonly content: string;
  readonly turns: readonly TraceTurnLine<RunAction, RunEvent>[];
};

export type BotRunResult = {
  readonly policy: BotPolicy["name"];
  readonly seed: string;
  readonly outcome: BotOutcome;
  readonly trace: BotTrace;
  readonly state: GameState;
};

export type RunBotOptions = {
  readonly createdAt?: string;
  readonly modelId?: string;
  readonly contentRef?: TraceContentRef;
  readonly runId?: string;
  readonly writer?: TraceWriter;
  readonly stallLimit?: number;
};

type StallTracker = {
  readonly previousActionKey: string | null;
  readonly previousProgressKey: string | null;
  readonly repeatCount: number;
};

const DEFAULT_CREATED_AT = "2026-06-12T00:00:00.000Z";
const DEFAULT_CONTENT_REF = {
  providerId: "fallback:old-stock",
  packVersion: "0.0.0",
} as const satisfies TraceContentRef;
const DEFAULT_STALL_LIMIT = 4;

export const runBot = (
  policy: BotPolicy,
  seed: string,
  provider: FloorContentProvider,
  maxTurns: number,
  options: RunBotOptions = {},
): BotRunResult => {
  assertMaxTurns(maxTurns);
  const started = startRun(seed, provider);
  if (!started.ok) {
    throw new Error(`failed to start run: ${started.error.message}`);
  }

  let state = started.state;
  let memory: BotMemory = createEmptyBotMemory();
  let stall: StallTracker = {
    previousActionKey: null,
    previousProgressKey: null,
    repeatCount: 0,
  };
  const createdAt = options.createdAt ?? DEFAULT_CREATED_AT;
  const runId =
    options.runId ?? traceRunId(`${policy.name}-${seed}`, createdAt);
  const recorder = createTraceRecorder<RunAction, RunEvent>({
    seed,
    createdAt,
    modelId: options.modelId ?? policy.name,
    contentRef: options.contentRef ?? DEFAULT_CONTENT_REF,
    runId,
    ...(options.writer === undefined ? {} : { writer: options.writer }),
  });
  const turns: TraceTurnLine<RunAction, RunEvent>[] = [];
  let maxTurnsHit = false;

  while (state.run.terminalStatus === "ACTIVE" && turns.length < maxTurns) {
    const view = createBotStateView(state, {
      policyName: policy.name,
      memory,
    });
    memory = updateBotMemory(memory, view);
    const decided = legalizeDecision(view, policy.decide(view));
    const breaker = breakStall(view, decided, stall, options.stallLimit);
    const action = breaker.action;
    stall = breaker.stall;

    const stepped = stepRun(state, action, provider);
    if (!stepped.ok) {
      throw new Error(
        `step failed at turn ${state.run.turn} for ${policy.name}: ${stepped.error.message}`,
      );
    }

    state = stepped.state;
    turns.push(
      recorder.recordTurn(action, {
        state: stepped.state,
        events: stepped.events,
      }),
    );

    if (action.kind === "take_hoard" && actionWasIllegal(stepped.events)) {
      const aborted = stepRun(state, { kind: "abort" }, provider);
      if (!aborted.ok) {
        throw new Error(`abort after illegal Hoard action failed: ${aborted.error.message}`);
      }
      state = aborted.state;
      turns.push(
        recorder.recordTurn(
          { kind: "abort" },
          {
            state: aborted.state,
            events: aborted.events,
          },
        ),
      );
    }
  }

  if (state.run.terminalStatus === "ACTIVE") {
    maxTurnsHit = true;
    const stepped = stepRun(state, { kind: "abort" }, provider);
    if (!stepped.ok) {
      throw new Error(`abort failed after maxTurns: ${stepped.error.message}`);
    }

    state = stepped.state;
    turns.push(
      recorder.recordTurn(
        { kind: "abort" },
        {
          state: stepped.state,
          events: stepped.events,
        },
      ),
    );
  }

  const summary = summarizeRun(state);

  return {
    policy: policy.name,
    seed,
    outcome: {
      terminal: state.run.terminalStatus,
      depth: summary.depth,
      turns: summary.turns,
      kills: summary.kills,
      hpRetention:
        state.player.hp.max <= 0 ? 0 : state.player.hp.current / state.player.hp.max,
      itemUses: turns.filter((turn) => turn.action.kind === "use_item").length,
      maxTurnsHit,
    },
    trace: {
      path: recorder.path,
      content: traceContent(recorder.header, turns),
      turns,
    },
    state,
  };
};

const legalizeDecision = (
  view: BotStateView,
  action: RunAction,
): RunAction => {
  if (hasAction(view, action)) {
    return action;
  }

  return fallbackAction(view);
};

const breakStall = (
  view: BotStateView,
  action: RunAction,
  stall: StallTracker,
  stallLimit = DEFAULT_STALL_LIMIT,
): { readonly action: RunAction; readonly stall: StallTracker } => {
  const progressKey = progressSignature(view);
  const key = actionKey(action);
  const repeatCount =
    stall.previousActionKey === key && stall.previousProgressKey === progressKey
      ? stall.repeatCount + 1
      : 1;

  if (repeatCount < stallLimit) {
    return {
      action,
      stall: {
        previousActionKey: key,
        previousProgressKey: progressKey,
        repeatCount,
      },
    };
  }

  const alternative = forcedAlternative(view, key);
  const alternativeKey = actionKey(alternative);

  return {
    action: alternative,
    stall: {
      previousActionKey: alternativeKey,
      previousProgressKey: progressKey,
      repeatCount: 1,
    },
  };
};

const forcedAlternative = (
  view: BotStateView,
  repeatedActionKey: string,
): RunAction => {
  const candidates = [
    ...view.availableActions.filter((action) => action.kind === "take_hoard"),
    ...view.availableActions.filter((action) => action.kind === "descend"),
    ...view.availableActions.filter((action) => action.kind === "pickup"),
    ...view.availableActions.filter((action) => action.kind === "attack"),
    ...view.availableActions.filter((action) => action.kind === "move"),
    ...view.availableActions.filter((action) => action.kind === "wait"),
    ...view.availableActions.filter((action) => action.kind === "use_item"),
    ...view.availableActions.filter((action) => action.kind === "abort"),
  ].filter((candidate) => actionKey(candidate) !== repeatedActionKey);

  return candidates[0] ?? { kind: "abort" };
};

const progressSignature = (view: BotStateView): string =>
  JSON.stringify({
    depth: view.run.depth,
    terminal: view.run.terminalStatus,
    position: view.player.position,
    hp: view.player.hp.current,
    fullness: view.player.fullness.current,
    inventory: view.player.inventory.map((item) => [
      item.itemInstanceId,
      item.definitionId,
      item.quantity,
    ]),
    enemies: view.visible.enemies.map((enemy) => [
      enemy.id,
      enemy.position,
      enemy.hp.current,
    ]),
    features: view.visible.features.map((feature) => [
      feature.id,
      feature.position,
    ]),
  });

const traceContent = (
  header: Parameters<typeof JSON.stringify>[0],
  turns: readonly TraceTurnLine<RunAction, RunEvent>[],
): string =>
  [JSON.stringify(header), ...turns.map((turn) => JSON.stringify(turn))].join(
    "\n",
  ) + "\n";

const assertMaxTurns = (maxTurns: number): void => {
  if (!Number.isSafeInteger(maxTurns) || maxTurns <= 0) {
    throw new RangeError("maxTurns must be a positive safe integer");
  }
};

const actionWasIllegal = (events: readonly RunEvent[]): boolean =>
  events.some(
    (event) =>
      (event.type === "run_action_illegal" || event.type === "action_illegal") &&
      "actionKind" in event.data,
  );

import { readFileSync } from "node:fs";

import "../../engine/systems/movement.js";
import { startRun, stepRun } from "../../engine/run/loop.js";
import { computeStateHash } from "../trace/hash.js";
import { parseTraceNdjson } from "./parse.js";
import { resolveContentProvider } from "./provider.js";
import type { DivergenceReport, ParsedTrace, VerifyResult } from "./types.js";

export const replayTrace = (
  trace: ParsedTrace
): VerifyResult | { readonly status: "unreadable"; readonly error: string } => {
  let provider;
  try {
    provider = resolveContentProvider(trace.header.contentRef);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { status: "unreadable", error: message };
  }

  const started = startRun(trace.header.seed, provider);
  if (!started.ok) {
    return {
      status: "unreadable",
      error: `failed to start run: ${started.error.message}`
    };
  }

  let state = started.state;

  for (const record of trace.turns) {
    const stepped = stepRun(state, record.action, provider);
    if (!stepped.ok) {
      return {
        status: "unreadable",
        error: `step failed at turn ${record.turn}: ${stepped.error.message}`
      };
    }

    state = stepped.state;
    const actualHash = computeStateHash(state);

    // Trace turn numbers use the recorder's post-step state convention.
    if (state.run.turn !== record.turn) {
      return {
        status: "diverged",
        report: {
          firstDivergentTurn: record.turn,
          expectedHash: record.stateHash,
          actualHash
        }
      };
    }

    if (actualHash !== record.stateHash) {
      return {
        status: "diverged",
        report: {
          firstDivergentTurn: record.turn,
          expectedHash: record.stateHash,
          actualHash
        }
      };
    }
  }

  return { status: "identical" };
};

export const verifyTraceContent = (content: string): VerifyResult => {
  let trace: ParsedTrace;
  try {
    trace = parseTraceNdjson(content);
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { status: "unreadable", error: message };
  }

  return replayTrace(trace);
};

export const verify = (tracePath: string): VerifyResult => {
  let content: string;
  try {
    content = readFileSync(tracePath, "utf8");
  } catch (error) {
    const message = error instanceof Error ? error.message : String(error);
    return { status: "unreadable", error: message };
  }

  return verifyTraceContent(content);
};

export type { DivergenceReport, VerifyResult };

import { describe, expect, it } from "vitest";

import { createFloorGeometrySlot, createTileGrid } from "../../engine/map/index.js";
import {
  createFogMemory,
  updateFogMemory,
  visibleCells,
} from "../../engine/map/fov.js";
import {
  createInitialEntityCounters,
  createInitialState,
  type GameState,
  type SerializableRecord,
  type TrapEntityInstance,
} from "../../engine/state/index.js";
import { verifyTraceContent } from "../replay/replay.js";
import { createFallbackFloorContentProvider } from "../fallback-provider.js";
import { validTrapDefinitionFixture } from "../../schemas/fixtures/entities.js";
import {
  aggressivePolicy,
  balancedPolicy,
  botPolicies,
  cautiousPolicy,
} from "./policies/index.js";
import { formatBotOutcomeTable } from "./batch.js";
import { runBot, type BotRunResult } from "./driver.js";
import { createBotStateView } from "./view.js";
import type { BotPolicy } from "./types.js";
import type { TraceWriter } from "../trace/recorder.js";
import type { RunAction } from "../../engine/run/loop.js";

const FALLBACK_SEEDS = Array.from(
  { length: 10 },
  (_, index) => `phase24-bot-${index + 1}`,
);
const MAX_TURNS = 900;

describe("bot policies", () => {
  it("runs 3 policies x 10 fallback seeds to terminal states with distinguishable aggregates", () => {
    const runs = botPolicies.flatMap((policy) =>
      FALLBACK_SEEDS.map((seed) =>
        runBot(policy, seed, createFallbackFloorContentProvider(), MAX_TURNS, {
          writer: memoryTraceWriter(`memory://${policy.name}/${seed}.ndjson`),
        }),
      ),
    );

    expect(runs).toHaveLength(30);
    expect(runs.every((run) => run.outcome.terminal !== "ACTIVE")).toBe(true);
    expect(
      runs.every((run) => !run.outcome.maxTurnsHit),
      maxTurnFailureReport(runs),
    ).toBe(true);
    expect(runs.every((run) => run.trace.turns.length <= MAX_TURNS)).toBe(true);

    const replaySpots = [
      runs.find((run) => run.policy === cautiousPolicy.name),
      runs.find((run) => run.policy === aggressivePolicy.name),
    ];

    for (const run of replaySpots) {
      expect(run).toBeDefined();
      if (run === undefined) {
        throw new Error("missing replay spot-check run");
      }
      expect(verifyTraceContent(run.trace.content)).toEqual({ status: "identical" });
    }

    const aggregates = aggregateByPolicy(runs);
    const differingMetrics = (["kills", "turns", "itemUses"] as const).filter(
      (metric) =>
        new Set(
          botPolicies.map((policy) =>
            aggregates.get(policy.name)?.[metric].join(",") ?? "",
          ),
        ).size >= 2,
    );

    expect(differingMetrics.length).toBeGreaterThanOrEqual(2);

    const table = formatBotOutcomeTable(
      runs.map((run) => ({
        policy: run.policy,
        seed: run.seed,
        terminal: run.outcome.terminal,
        depth: run.outcome.depth,
        turns: run.outcome.turns,
        kills: run.outcome.kills,
        hpRetention: run.outcome.hpRetention,
        itemUses: run.outcome.itemUses,
        tracePath: run.trace.path,
      })),
    );
    if (printBotTableRequested()) {
      console.log(`\n${table}`);
    }
    expect(table).toContain("policy");
    expect(table.split("\n")).toHaveLength(32);
  }, 120_000);

  it("does not expose out-of-sight hidden traps to policy decisions", () => {
    const withoutTrap = hiddenTrapFixture(false);
    const withTrap = hiddenTrapFixture(true);

    for (const policy of botPolicies) {
      const first = policy.decide(
        // No memory is supplied: this verifies only the public view helper.
        createViewForPolicy(withoutTrap, policy),
      );
      const second = policy.decide(createViewForPolicy(withTrap, policy));

      expect(actionFingerprint(second)).toBe(actionFingerprint(first));
    }
  });

  it("breaks repeated no-progress action loops", () => {
    const waitPolicy: BotPolicy = {
      name: balancedPolicy.name,
      description: "Always waits so the driver must force a productive alternative.",
      decide: () => ({ kind: "wait" }),
    };
    const run = runBot(
      waitPolicy,
      "phase24-stall-breaker",
      createFallbackFloorContentProvider(),
      8,
      {
        stallLimit: 3,
        writer: memoryTraceWriter("memory://stall-breaker.ndjson"),
      },
    );
    const actions = run.trace.turns.map((turn) => turn.action.kind);

    expect(actions.slice(0, 3)).toEqual(["wait", "wait", "move"]);
  });
});

const createViewForPolicy = (state: GameState, policy: BotPolicy) => {
  return createBotStateView(state, { policyName: policy.name });
};

const hiddenTrapFixture = (includeTrap: boolean): GameState => {
  const grid = createTileGrid({ width: 6, height: 6 });
  const player = { x: 1, y: 1 };
  const fog = updateFogMemory(createFogMemory(grid), grid, visibleCells(grid, player, 1));
  const state = createInitialState("fog-honesty");
  const trap: TrapEntityInstance = {
    id: "trap#1",
    kind: "trap",
    definition: validTrapDefinitionFixture,
    position: { x: 5, y: 5 },
    currentHP: null,
    statuses: [],
    behaviorRuntime: {},
    armed: true,
  };

  return {
    ...state,
    floor: {
      ...state.floor,
      geometry: {
        ...createFloorGeometrySlot(state.floor.geometry.refId, grid),
        opaque: {
          ...grid,
          fog,
        } as unknown as SerializableRecord,
      },
    },
    player: {
      ...state.player,
      position: player,
    },
    entities: includeTrap ? { [trap.id]: trap } : {},
    ids: {
      ...state.ids,
      entityCounters: includeTrap
        ? { ...createInitialEntityCounters(), trap: 1 }
        : createInitialEntityCounters(),
    },
  };
};

type PolicyAggregates = {
  readonly kills: readonly number[];
  readonly turns: readonly number[];
  readonly itemUses: readonly number[];
};

const aggregateByPolicy = (
  runs: readonly BotRunResult[],
): ReadonlyMap<BotPolicy["name"], PolicyAggregates> => {
  const entries = botPolicies.map((policy) => {
    const policyRuns = runs.filter((run) => run.policy === policy.name);
    return [
      policy.name,
      {
        kills: policyRuns.map((run) => run.outcome.kills),
        turns: policyRuns.map((run) => run.outcome.turns),
        itemUses: policyRuns.map((run) => run.outcome.itemUses),
      },
    ] as const;
  });

  return new Map(entries);
};

const maxTurnFailureReport = (runs: readonly BotRunResult[]): string =>
  runs
    .filter((run) => run.outcome.maxTurnsHit)
    .map(
      (run) =>
        `${run.policy}/${run.seed} ${run.outcome.terminal} d${run.outcome.depth} t${run.outcome.turns} kills=${run.outcome.kills} items=${run.outcome.itemUses}`,
    )
    .join("\n");

const printBotTableRequested = (): boolean => {
  const host = globalThis as {
    readonly process?: {
      readonly env?: {
        readonly PRINT_BOT_TABLE?: string;
      };
    };
  };

  return host.process?.env?.PRINT_BOT_TABLE === "1";
};

const actionFingerprint = (action: RunAction): string =>
  JSON.stringify(action, Object.keys(action).sort());

const memoryTraceWriter = (path: string): TraceWriter => {
  return {
    path,
    writeHeader: () => {},
    appendTurn: () => {},
  };
};

import { appendFileSync, mkdirSync, writeFileSync } from "node:fs";

import { ENGINE_VERSION, PROTOCOL_VERSION } from "../../schemas/protocol.js";
import type { EngineLogEvent, GameState } from "../../engine/state/index.js";
import { computeStateHash } from "./hash.js";

export type TraceContentRef = {
  readonly providerId: string;
  readonly packVersion: string;
};

export type TraceHeader = {
  readonly recordType: "header";
  readonly protocolVersion: typeof PROTOCOL_VERSION;
  readonly engineVersion: string;
  readonly modelId: string;
  readonly contentRef: TraceContentRef;
  readonly seed: string;
  readonly createdAt: string;
  readonly runId: string;
};

export type TraceTurnLine<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly turn: number;
  readonly action: Action;
  readonly events: readonly Event[];
  readonly stateHash: string;
};

export type EngineLikeStepResult<
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly state: GameState;
  readonly events: readonly Event[];
};

export type EngineLikeSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly state: GameState;
  readonly getAvailableActions?: () => readonly Action[];
  readonly step: (action: Action) => EngineLikeStepResult<Event>;
  readonly isTerminal?: () => boolean;
};

export type RecordedSession<
  Action,
  Event extends EngineLogEvent = EngineLogEvent
> = EngineLikeSession<Action, Event> & {
  readonly trace: TraceRecorder<Action, Event>;
};

export type TraceRecorderOptions = {
  readonly seed: string;
  readonly createdAt: string;
  readonly modelId: string;
  readonly contentRef: TraceContentRef;
  readonly runId?: string;
  readonly writer?: TraceWriter;
};

export type TraceRecorder<
  Action = unknown,
  Event extends EngineLogEvent = EngineLogEvent
> = {
  readonly header: TraceHeader;
  readonly path: string;
  readonly recordTurn: (
    action: Action,
    result: EngineLikeStepResult<Event>
  ) => TraceTurnLine<Action, Event>;
};

export type TraceWriter = {
  readonly path: string;
  readonly writeHeader: (header: TraceHeader) => void;
  readonly appendTurn: <Action, Event extends EngineLogEvent>(
    line: TraceTurnLine<Action, Event>
  ) => void;
};

export type TraceFsAdapter = {
  readonly makeDir: (path: string) => void;
  readonly writeNewFile: (path: string, contents: string) => void;
  readonly appendFile: (path: string, contents: string) => void;
};

export type FileTraceWriterOptions = {
  readonly runId: string;
  readonly rootDir?: string;
  readonly fs?: TraceFsAdapter;
};

export const createTraceRecorder = <
  Action,
  Event extends EngineLogEvent = EngineLogEvent
>(
  options: TraceRecorderOptions
): TraceRecorder<Action, Event> => {
  const runId = options.runId ?? traceRunId(options.seed, options.createdAt);
  const writer = options.writer ?? createFileTraceWriter({ runId });
  const header: TraceHeader = {
    recordType: "header",
    protocolVersion: PROTOCOL_VERSION,
    engineVersion: ENGINE_VERSION,
    modelId: options.modelId,
    contentRef: options.contentRef,
    seed: options.seed,
    createdAt: options.createdAt,
    runId
  };

  writer.writeHeader(header);

  return {
    header,
    path: writer.path,
    recordTurn: (action, result) => {
      // Trace turn numbers use the recorder's post-step state convention.
      const line: TraceTurnLine<Action, Event> = {
        turn: result.state.run.turn,
        action,
        events: result.events,
        stateHash: computeStateHash(result.state)
      };
      writer.appendTurn(line);
      return line;
    }
  };
};

export const record = <Action, Event extends EngineLogEvent = EngineLogEvent>(
  session: EngineLikeSession<Action, Event>,
  options: TraceRecorderOptions
): RecordedSession<Action, Event> => {
  const trace = createTraceRecorder<Action, Event>(options);

  return {
    get state() {
      return session.state;
    },
    getAvailableActions: session.getAvailableActions?.bind(session),
    isTerminal: session.isTerminal?.bind(session),
    step: (action) => {
      const result = session.step(action);
      trace.recordTurn(action, result);
      return result;
    },
    trace
  };
};

export const createFileTraceWriter = (
  options: FileTraceWriterOptions
): TraceWriter => {
  const rootDir = trimTrailingSlash(options.rootDir ?? "runs");
  const dir = `${rootDir}/${options.runId}`;
  const path = `${dir}/trace.ndjson`;
  const fs = options.fs ?? nodeTraceFsAdapter;

  return {
    path,
    writeHeader: (header) => {
      fs.makeDir(dir);
      fs.writeNewFile(path, `${JSON.stringify(header)}\n`);
    },
    appendTurn: (line) => {
      fs.appendFile(path, `${JSON.stringify(line)}\n`);
    }
  };
};

export const traceRunId = (seed: string, createdAt: string): string =>
  `run-${runIdComponent(seed)}-${runIdComponent(createdAt)}`;

const runIdComponent = (value: string): string => {
  const component = value
    .replace(/[^A-Za-z0-9._-]+/g, "-")
    .replace(/^-+|-+$/g, "");

  if (component.length === 0) {
    return "blank";
  }

  return component.slice(0, 80);
};

const trimTrailingSlash = (value: string): string => value.replace(/\/+$/g, "");

const nodeTraceFsAdapter: TraceFsAdapter = {
  makeDir: (path) => {
    mkdirSync(path, { recursive: true });
  },
  writeNewFile: (path, contents) => {
    writeFileSync(path, contents, { encoding: "utf8", flag: "wx" });
  },
  appendFile: (path, contents) => {
    appendFileSync(path, contents, { encoding: "utf8" });
  }
};

