  const recorded: RecordedSession<RunAction, RunEvent> = record(
    {
      get state() {
        return state;
      },
      step: baseStep,
    },
    traceOptions,
  );

  return {
    getState: () => recorded.state,
    setState: (next) => {
      state = next;
    },
    step: (action) => recorded.step(action),
